const body = $input.first().json.body;
const message = body.message;

// Extraer función ejecutada
const toolCall = message.toolCallList[0];
const functionName = toolCall.function.name;
const functionArgs = toolCall.function.arguments;

// Extraer conversación limpia (solo role + message de humanos y bot)
const conversacion = (message.artifact?.messages || [])
  .filter(m => m.role === 'user' || m.role === 'bot')
  .map(m => ({ rol: m.role, mensaje: m.message }));

// Extraer último mensaje del usuario (suele tener email/fecha)
const ultimoUsuario = conversacion
  .filter(m => m.rol === 'user')
  .slice(-1)[0]?.mensaje || '';

// Construir objeto limpio
return [{
  json: {
    funcion: functionName,
    argumentos: functionArgs,
    ultimo_mensaje_usuario: ultimoUsuario,
    conversacion: conversacion,
    assistant_id: message.assistant?.id || '',
    chat_id: message.chat?.id || '',
    timestamp: message.timestamp
  }
}];
